-- Specification 
CREATE OR REPLACE PACKAGE pkg_hello AS
  PROCEDURE show_msg;
END pkg_hello;
/
-- Body 
CREATE OR REPLACE PACKAGE BODY pkg_hello AS
  PROCEDURE show_msg IS
  BEGIN
    DBMS_OUTPUT.PUT_LINE('Hello Oracle');
  END show_msg;
END pkg_hello;
/
EXEC pkg_hello.show_msg;

CREATE OR REPLACE PACKAGE pkg_emp AS
  PROCEDURE get_details(p_no NUMBER);
END pkg_emp;
/
CREATE OR REPLACE PACKAGE BODY pkg_emp AS
  PROCEDURE get_details(p_no NUMBER) IS
    v_n VARCHAR2(20); v_s NUMBER;
  BEGIN
    SELECT ENAME, SAL INTO v_n, v_s FROM EMP WHERE EMPNO = p_no;
    DBMS_OUTPUT.PUT_LINE(v_n || ' earns ' || v_s);
  END get_details;
END pkg_emp;
/
EXEC pkg_emp.get_details(7839);

CREATE OR REPLACE PACKAGE pkg_math AS
  FUNCTION get_sq(n NUMBER) RETURN NUMBER;
END pkg_math;
/
CREATE OR REPLACE PACKAGE BODY pkg_math AS
  FUNCTION get_sq(n NUMBER) RETURN NUMBER IS
  BEGIN
    RETURN n * n;
  END get_sq;
END pkg_math;
/
SELECT pkg_math.get_sq(8) FROM DUAL;

CREATE OR REPLACE PACKAGE pkg_mixed AS
  PROCEDURE greet(name VARCHAR2);
  FUNCTION add_tax(sal NUMBER) RETURN NUMBER;
END pkg_mixed;
/
CREATE OR REPLACE PACKAGE BODY pkg_mixed AS
  PROCEDURE greet(name VARCHAR2) IS
  BEGIN DBMS_OUTPUT.PUT_LINE('Hi ' || name); END;
  FUNCTION add_tax(sal NUMBER) RETURN NUMBER IS
  BEGIN RETURN sal * 1.10; END;
END pkg_mixed;

CREATE OR REPLACE PACKAGE pkg_emp_ops AS
  PROCEDURE add_emp(id NUMBER, name VARCHAR2);
  PROCEDURE del_emp(id NUMBER);
END pkg_emp_ops;
/
CREATE OR REPLACE PACKAGE BODY pkg_emp_ops AS
  PROCEDURE add_emp(id NUMBER, name VARCHAR2) IS
  BEGIN INSERT INTO EMP(EMPNO, ENAME) VALUES (id, name); END;
  PROCEDURE del_emp(id NUMBER) IS
  BEGIN DELETE FROM EMP WHERE EMPNO = id; END;
END pkg_emp_ops;

CREATE OR REPLACE PACKAGE pkg_global AS
  g_val NUMBER := 100;
  PROCEDURE show_val;
END pkg_global;
/
CREATE OR REPLACE PACKAGE BODY pkg_global AS
  PROCEDURE show_val IS
  BEGIN
    DBMS_OUTPUT.PUT_LINE('Global Value: ' || g_val);
  END show_val;
END pkg_global;
/
EXEC pkg_global.show_val;

CREATE OR REPLACE PACKAGE pkg_config AS
  c_comp CONSTANT VARCHAR2(20) := 'Oracle Corp';
END pkg_config;
/
BEGIN
  DBMS_OUTPUT.PUT_LINE('Company: ' || pkg_config.c_comp);
END;

CREATE OR REPLACE PACKAGE pkg_state AS
  pv_count NUMBER := 0;
  PROCEDURE call_me;
END pkg_state;
/
CREATE OR REPLACE PACKAGE BODY pkg_state AS
  PROCEDURE call_me IS
  BEGIN
    pv_count := pv_count + 1;
    DBMS_OUTPUT.PUT_LINE('Call Number: ' || pv_count);
  END call_me;
END pkg_state;
/
EXEC pkg_state.call_me;
EXEC pkg_state.call_me;

CREATE OR REPLACE PACKAGE pkg_share AS
  g_status VARCHAR2(20);
  PROCEDURE set_status(s VARCHAR2);
  PROCEDURE print_status;
END pkg_share;
/
CREATE OR REPLACE PACKAGE BODY pkg_share AS
  PROCEDURE set_status(s VARCHAR2) IS BEGIN g_status := s; END;
  PROCEDURE print_status IS BEGIN DBMS_OUTPUT.PUT_LINE('Status: ' || g_status); END;
END pkg_share;
/
BEGIN
  pkg_share.set_status('Active');
  pkg_share.print_status;
END;
